import { MinPriorityQueue } from '@datastructures-js/priority-queue';

function solve(n, edges) {
    // Build adjacency list
    const adj = Array.from({ length: n }, () => []);
    const reverseAdj = Array.from({ length: n }, () => []); // To track incoming edges for potential reversal
    for (const [u, v, w] of edges) {
        adj[u].push([v, w, false]); // [neighbor, weight, isReversed]
        reverseAdj[v].push([u, w]); // [from, weight]
    }

    // dist[node][used]: min distance to node with used reversals (0 or 1)
    const dist = Array.from({ length: n }, () => [Infinity, Infinity]);
    dist[0][0] = 0;

    const pq = new MinPriorityQueue({ priority: (item) => item.cost });
    pq.enqueue({ node: 0, used: 0, cost: 0 });

    while (!pq.isEmpty()) {
        const { node, used, cost } = pq.dequeue().element;
        if (node === n - 1) {
            return cost;
        }
        if (cost > dist[node][used]) {
            continue;
        }

        // Normal edges
        for (const [v, w, isReversed] of adj[node]) {
            const newCost = cost + w;
            if (newCost < dist[v][used]) {
                dist[v][used] = newCost;
                pq.enqueue({ node: v, used, cost: newCost });
            }
        }

        // Try reversing an incoming edge if not used yet
        if (used === 0) {
            for (const [u, w] of reverseAdj[node]) {
                const newCost = cost + 2 * w;
                if (newCost < dist[u][1]) {
                    dist[u][1] = newCost;
                    pq.enqueue({ node: u, used: 1, cost: newCost });
                }
            }
        }
    }

    const res = Math.min(dist[n - 1][0], dist[n - 1][1]);
    return res === Infinity ? -1 : res;
}

